-- ==========================================
-- MOVIMIENTOS DE INVENTARIO DE PRUEBA
-- (usando codigos de productos con precio)
-- ==========================================
SELECT p.id, 'entrada', 50, 0, 50, 'compra', 'Carlos', now() - interval '10 days'
FROM productos p WHERE p.codigo = 'PREI2'
UNION ALL
SELECT p.id, 'entrada', 30, 0, 30, 'compra', 'Luis', now() - interval '9 days'
FROM productos p WHERE p.codigo = 'PREI8'
UNION ALL
SELECT p.id, 'entrada', 100, 0, 100, 'compra', 'Carlos', now() - interval '8 days'
FROM productos p WHERE p.codigo = 'PCPI20'
UNION ALL
SELECT p.id, 'salida', 20, 100, 80, 'venta', 'Luis', now() - interval '7 days'
FROM productos p WHERE p.codigo = 'PCPI20'
UNION ALL
SELECT p.id, 'entrada', 40, 0, 40, 'compra', 'Carlos', now() - interval '6 days'
FROM productos p WHERE p.codigo = 'PCPI26'
UNION ALL
SELECT p.id, 'entrada', 60, 0, 60, 'compra', 'Luis', now() - interval '5 days'
FROM productos p WHERE p.codigo = 'PCEI38'
UNION ALL
SELECT p.id, 'salida', 10, 50, 40, 'venta', 'Carlos', now() - interval '4 days'
FROM productos p WHERE p.codigo = 'PREI2'
UNION ALL
SELECT p.id, 'entrada', 25, 0, 25, 'compra', 'Luis', now() - interval '3 days'
FROM productos p WHERE p.codigo = 'PREI14'
UNION ALL
SELECT p.id, 'salida', 15, 30, 15, 'venta', 'Carlos', now() - interval '2 days'
FROM productos p WHERE p.codigo = 'PREI8'
UNION ALL
SELECT p.id, 'entrada', 35, 0, 35, 'compra', 'Luis', now() - interval '1 day'
FROM productos p WHERE p.codigo = 'PCPI32';

-- Actualizar stock_actual de los productos que tuvieron movimientos
UPDATE productos SET stock_actual = 40 WHERE codigo = 'PREI2';
UPDATE productos SET stock_actual = 15 WHERE codigo = 'PREI8';
UPDATE productos SET stock_actual = 25 WHERE codigo = 'PREI14';
UPDATE productos SET stock_actual = 80 WHERE codigo = 'PCPI20';
UPDATE productos SET stock_actual = 40 WHERE codigo = 'PCPI26';
UPDATE productos SET stock_actual = 35 WHERE codigo = 'PCPI32';
UPDATE productos SET stock_actual = 60 WHERE codigo = 'PCEI38';

